typedef struct _FD_DEVICEMETRICS {   FLONG    flRealizedType;
POINTE   pteBase;   POINTE   pteSide;   LONG     lD;
FIX      fxMaxAscender;   FIX      fxMaxDescender;   POINTL   ptlUnderline1;   POINTL   ptlStrikeOut;   POINTL   ptlULThickness;   POINTL   ptlSOThickness;
ULONG    cxMax;   ULONG    cyMax;
ULONG    cjGlyphMax;   FD_XFORM fdxQuantized;
LONG     lNonLinearExtLeading;   LONG     lNonLinearIntLeading;   LONG     lNonLinearMaxCharWidth;   LONG     lNonLinearAvgCharWidth;
LONG     lMinA;   LONG     lMinC;   LONG     lMinD;
LONG     alReserved[1];
} FD_DEVICEMETRICS, *PFD_DEVICEMETRICS; 成员
flRealizedType
是一组快捷键标志。 此值可以是以下值的组合： FDM_TYPE_BM_SIDE_CONST
用于水平和垂直书写的加速键。 如果设置了此标志，则字体具有所有位图的常量高度。在水平情况下，这意味着 cy 维度是常量;在垂直情况下，这意味着 cx 维度是常量。 此加
速器不用于轮廓。

